{
  "mode": "method",
  "tests": [
    {
      "name": "get_terms_with_valid_title",
      "input": {
        "page": 1,
        "perPage": 25,
        "title": "User Agreement"
      },
      "output": {
        "terms": [
          {
            "id": "0375a1e9-ed7d-4683-bcf3-f21114bd26c9",
            "title": "User Agreement",
            "content": "Terms of use for users."
          }
        ],
        "total": 1
      },
      "notes": "Validates retrieval of terms by title."
    },
    {
      "name": "get_terms_with_empty_title",
      "input": {
        "page": 1,
        "perPage": 25,
        "title": ""
      },
      "output": {
        "terms": [],
        "total": 0
      },
      "notes": "Tests response when title is empty, expecting no terms."
    },
    {
      "name": "save_term_with_valid_data",
      "input": {
        "title": "Privacy Policy",
        "content": "<p>Privacy terms...</p>",
        "type": "standard",
        "agreeabilityType": "mandatory"
      },
      "output": {
        "success": true,
        "id": "new-term-id"
      },
      "notes": "Validates saving a new term with valid data."
    },
    {
      "name": "save_term_with_missing_title",
      "input": {
        "title": "",
        "content": "<p>Privacy terms...</p>",
        "type": "standard",
        "agreeabilityType": "mandatory"
      },
      "output": {
        "success": false,
        "error": "Title is required."
      },
      "notes": "Tests saving a term with missing title, expecting failure."
    },
    {
      "name": "delete_term_with_valid_id",
      "input": {
        "id": "0375a1e9-ed7d-4683-bcf3-f21114bd26c9"
      },
      "output": {
        "success": true
      },
      "notes": "Validates deletion of a term with a valid ID."
    },
    {
      "name": "delete_term_with_invalid_id",
      "input": {
        "id": "invalid-id"
      },
      "output": {
        "success": false,
        "error": "Term not found."
      },
      "notes": "Tests deletion of a term with an invalid ID, expecting failure."
    },
    {
      "name": "add_user_to_term_with_valid_handle",
      "input": {
        "termId": "0375a1e9-ed7d-4683-bcf3-f21114bd26c9",
        "handle": "validUserHandle"
      },
      "output": {
        "success": true
      },
      "notes": "Validates adding a user to a term with a valid handle."
    },
    {
      "name": "add_user_to_term_with_invalid_handle",
      "input": {
        "termId": "0375a1e9-ed7d-4683-bcf3-f21114bd26c9",
        "handle": "invalidUserHandle"
      },
      "output": {
        "success": false,
        "error": "User not found."
      },
      "notes": "Tests adding a user to a term with an invalid handle, expecting failure."
    }
  ],
  "assumptions": "All API endpoints are functional and return expected data formats.",
  "notes": "Ensure to test both valid and invalid scenarios for comprehensive coverage."
}
